SELECT s.spu_id AS spuId, s.brand AS brandName, s.title, s.sub_title AS subTitle, s.main_img AS mainImg, s.price AS price, s.status, s.updated_at AS updatedAt FROM goods_spu s WHERE s.spu_id IN
#{spuId}
ORDER BY s.sort DESC

SELECT gp.id AS id, gp.spu_id AS spuId, cp.param_name AS attrName, gp.param_value AS attrValue, cp.sort AS sort FROM goods_param gp inner join goods_category_param cp ON gp.template_id = cp.param_id WHERE gp.spu_id IN
#{id}
ORDER BY cp.sort DESC

select img_id AS imgId, spu_id AS spuId, img_url AS imgUrl, description AS description, sort AS sort, is_main AS isMain from goods_image where spu_id IN
#{id}
order by sort DESC

select * from goods_custom_param g where spu_id IN
#{id}
order by sort desc

SELECT COUNT(*) FROM goods_image WHERE spu_id = #{spuId}
UNION ALL
SELECT COUNT(*) FROM goods_tag_relation WHERE spu_id = #{spuId}
UNION ALL
SELECT COUNT(*) FROM goods_custom_param WHERE spu_id = #{spuId}

SELECT s.spu_id as spuId, s.sub_title AS subTitle, s.main_img AS mainImg, s.price AS price, st.buy_num AS saleCount FROM goods_spu s LEFT JOIN goods_stat st ON s.spu_id = st.spu_id WHERE s.spu_id IN
#{id}
ORDER BY s.sort DESC
